      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../lib/errors');

const projects = [];

const createProject = async (project) => {
  if (!project.name) {
    throw sendError(400, 'BAD_REQUEST', 'Project name is required');
  }
  const newProject = { id: randomUUID(), ...project };
  projects.push(newProject);
  return newProject;
};

module.exports = { createProject };
